import { SECONDARY_PATTERNS as ENGINE_SP } from '../engine';

function withTriggers(patterns) {
  const out = {};
  Object.keys(patterns).forEach(k => {
    out[k] = { ...patterns[k] };
    if (ENGINE_SP[k]?.trigger) out[k].trigger = ENGINE_SP[k].trigger;
  });
  return out;
}

